B = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz'
T = {e:i for i,e in enumerate(B)}

def decode(s):
    z = []
    for c in s.split('@'):
        x = 0
        for i in c: x = 62*x+T[i]
        z.append(x)
    return z
